// Guard the proof on the implication antecedent so we can use both
// `ensures` conjuncts as hypotheses inside the `if`.
if (({ let (next_idx, count) = r1;
        next_idx + count <= COMMIT_MASK_BITS
        && (forall |t| next_idx <= t < next_idx + count ==> self_@.contains(t))
    }) && ({ let (next_idx, count) = r2;
        next_idx + count <= COMMIT_MASK_BITS
        && (forall |t| next_idx <= t < next_idx + count ==> self_@.contains(t))
    })) {
    // Restate the arithmetic bounds explicitly so they are first-class
    // facts (not buried inside a `let`-pattern destructure).
    assert(r1.0 + r1.1 <= COMMIT_MASK_BITS);
    assert(r2.0 + r2.1 <= COMMIT_MASK_BITS);

    // Restate both membership forall clauses with a unified
    // `#[trigger] self_@.contains(t)` pattern so the two quantifiers
    // share a trigger and z3 can line them up against the same ground
    // term during instantiation.
    assert(forall |t: int| r1.0 as int <= t < r1.0 as int + r1.1 as int
        ==> #[trigger] self_@.contains(t));
    assert(forall |t: int| r2.0 as int <= t < r2.0 as int + r2.1 as int
        ==> #[trigger] self_@.contains(t));

    // Concrete boundary witnesses: when the run is non-empty, the
    // endpoints `r*.0` and `r*.0 + r*.1 - 1` are inside the run, so
    // `self_@.contains(...)` follows from the restated forall above.
    // These ground terms give z3 explicit instantiation hooks for the
    // unified trigger pattern when matching r1 and r2 across each
    // other's forall.
    if r1.1 > 0 {
        assert(self_@.contains(r1.0 as int));
        assert(self_@.contains(r1.0 as int + r1.1 as int - 1));
    }
    if r2.1 > 0 {
        assert(self_@.contains(r2.0 as int));
        assert(self_@.contains(r2.0 as int + r2.1 as int - 1));
    }

    // Cross-restatement: also state each forall in terms of the *other*
    // result's bounds, instantiated at the same `t` so that z3 has the
    // matching ground-term scaffolding it needs to relate r1 and r2.
    assert(forall |t: int| r1.0 as int <= t < r1.0 as int + r1.1 as int
        && r2.0 as int <= t < r2.0 as int + r2.1 as int
        ==> #[trigger] self_@.contains(t));
}
